from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismEvalNode(BaseNode):
    name = "Prism: Eval Python"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("code", "string", widget_type="text_area", default="result = core.version")
        self.add_output("result", "any")
        self.add_output("success", "bool")
        self.add_output("error", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        code = inputs.get('code') or ''
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph.")
            return {'result': '', 'success': False, 'error': 'No core provided.'}
        ns = {'core': core, 'result': ''}
        try:
            exec(code, ns)
            result = ns.get('result', '')
            if result is None:
                result = ''
            self.log_success(f"Eval ok. result={result!r}")
            await self.set_output('exec_out', True)
            return {'result': result, 'success': True, 'error': ''}
        except Exception as e:
            self.log_error(f"Eval failed: {e}")
            return {'result': '', 'success': False, 'error': str(e)}

def register_node():
    return PrismEvalNode
